# 3. Insert Data
# Assuming the XML structure is root -> record (array)
my $records = $data->{record};

# Handle case where there is only one record (XML::Simple returns a hash instead of array)
if (ref($records) eq 'HASH') {
    $records = [$records];
}

my $sth = $dbh->prepare("INSERT INTO users (id, name, email) VALUES (?, ?, ?)");

foreach my $rec (@$records) {
