    updated_email TEXT;
BEGIN
    -- Step 1: Logical deduction - Verify existence and current state
    SELECT email_address INTO current_email FROM clients WHERE id = 'Cust1234';

    IF current_email IS NULL THEN
        RAISE EXCEPTION 'The customer either does not exist or does not have an email address.';
