    SELECT email_address INTO updated_email FROM clients WHERE id = 'Cust1234';

    IF updated_email != new_email_val THEN
        RAISE EXCEPTION 'Email update failed verification.';
    END IF;

    RAISE NOTICE 'Customer Cust1234 email updated successfully to %', updated_email;
END
$$;
"""
