def encrypt(s: str, sys_name: str = 'unix') -> str:
    """Encrypts a string, moves each alphabet character by 13 places in upper case and 15 places in lower case. Considers system end line characters.
    """
    def match_only_english_alpha(char):
        if (char >= 'a' and char <= 'z') or (char >= 'A' and char <= 'Z'):
            return True
        else:
            return False

    def rotate(c, offset):
        z = 'z' if c.islower() else 'Z'
        a = 'a' if c.islower() else 'A'
        return chr((ord(c) - ord(a) + offset) % 26 + ord(a))

    def new_line_handler(c):
        if c == '\n':
            if sys_name == 'unix':
                return ''
            elif sys_name == 'windows':
                return '\r\n'
        return c

    mappings = {c: (new_line_handler(c) if not match_only_english_alpha(c) else 
                    (rotate(c, 13) if c.isupper() else rotate(c, 15))) for c in set(s)}

    return ''.join(mappings.get(c, c) for c in s)

