class TrieNode:
    def __init__(self):
        self.children = {}

class Trie:
    def __init__(self):
        self.root = TrieNode()
        self.count = 0

    def insert(self, s, start_idx):
        node = self.root
        for i in range(start_idx, len(s)):
            char = s[i]
            if char not in node.children:
