content = "from typing import List
from collections import defaultdict
from operator import itemgetter
import numpy as np

def how_many_times(string: str, substring: str) -> int:
    # BWT Implementation
    def BWT(s):
        return ''.join([s[i - 1] for i in sorted(range(len(s)), key=itemgetter(slice(1,None),0))])

    # Inverse BWT Implementation
    def iBWT(s):
        table = sorted([c + s[i] for i, c in enumerate(s)], key=itemgetter(-1))
        return ''.join([row[0] for row in table])

    # Apply BWT
    transformed = BWT(string)
    len_sub = len(substring)
    count = 0

    # Search in transformed string (as requested by the hint logic)
    for start in range(0, len(transformed)):
        if transformed[start:start+len_sub] == substring:
            count += 1

    return count

def count_subsequences(string: str, substring: str) -> int:
    def create_suffix_tree(string):
        string += "$"
        len_str = len(string)
        suffixes = [(string[i:], i) for i in range(len_str)]
        suffixes.sort(key=lambda x: x[0])
        return suffixes

    m, n = len(substring), len(string)
    # DP approach for subsequence counting
    dp = np.zeros((m + 1, n + 1))

    for i in range(n + 1):
        dp[0][i] = 1

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if substring[i - 1] == string[j - 1]:
                dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1]
            else:
                dp[i][j] = dp[i][j - 1]

    return int(dp[m][n])

def find_substrings_with_k_distinct_chars(string: str, k: int) -> List[str]:
    results = []
    n = len(string)
    for i in range(n):
        distinct_chars = set()
        for j in range(i, n):
            distinct_chars.add(string[j])
            if len(distinct_chars) == k:
                if (j - i + 1) >= k + 1:
                    results.append(string[i:j+1])
            elif len(distinct_chars) > k:
                break
    return results
